update.foreach:
UPDATE snail_ai_client_node
SET max_concurrent      = #{item.maxConcurrent},
active_chats        = #{item.activeChats},
supported_providers = #{item.supportedProviders},
labels              = #{item.labels},
expire_dt           = #{item.expireDt}
WHERE app_id  = #{item.appId}
AND host_id = #{item.hostId}
